query.sparql:
SELECT ?animal ?animalLabel WHERE {
  ?animal wdt:P798 ?militaryDesignation.
  ?militaryDesignation wdt:P7779 wd:Q625657.
  ?animal rdfs:label ?animalLabel.
  FILTER(LANG(?animalLabel) = "en")
}

SELECT ?character WHERE {
  ?character p:P451 ?statement1.
  ?statement1 p:P451 wd:Q4205826.
  ?character p:P451 ?statement2.
  ?statement2 p:P451 wd:Q4463198.
}

SELECT ?founder WHERE {
  wd:Q27050 p:P102 ?membership.
  ?membership ps:P102 wd:Q13218629.
  ?founder wdt:P199 wd:Q27050.  # Founders of Tencent
}
